const ethers = require('ethers');

// Configuration
const config = {
  rpcUrl: 'https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID',
  privateKey: '0xYOUR_PRIVATE_KEY_HERE',
  contractAddress: '0xYOUR_CONTRACT_ADDRESS',
  gasLimit: 21000,
  maxFeePerGas: ethers.parseUnits('50', 'gwei'),
  maxPriorityFeePerGas: ethers.parseUnits('2', 'gwei')
};

// Contract ABI example
const contractABI = [
  'function transfer(address to, uint256 amount) returns (bool)',
  'function balanceOf(address owner) view returns (uint256)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function mint(address to, uint256 amount)',
  'event Transfer(address indexed from, address indexed to, uint256 value)'
];

class Web3Service {
  constructor(config) {
    this.provider = new ethers.JsonRpcProvider(config.rpcUrl);
    this.wallet = new ethers.Wallet(config.privateKey, this.provider);
    this.contractAddress = config.contractAddress;
    this.gasLimit = config.gasLimit;
    this.maxFeePerGas = config.maxFeePerGas;
    this.maxPriorityFeePerGas = config.maxPriorityFeePerGas;
  }

  async getBalance(address) {
    const balance = await this.provider.getBalance(address);
    return ethers.formatEther(balance);
  }

  async sendETH(toAddress, amountInEther) {
    const tx = {
      to: toAddress,
      value: ethers.parseEther(amountInEther.toString()),
      gasLimit: this.gasLimit,
      maxFeePerGas: this.maxFeePerGas,
      maxPriorityFeePerGas: this.maxPriorityFeePerGas
    };

    const transaction = await this.wallet.sendTransaction(tx);
    const receipt = await transaction.wait();
    
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status
    };
  }

  async sendETHWithEstimatedGas(toAddress, amountInEther) {
    const tx = {
      to: toAddress,
      value: ethers.parseEther(amountInEther.toString())
    };

    const estimatedGas = await this.provider.estimateGas({
      ...tx,
      from: this.wallet.address
    });

    tx.gasLimit = estimatedGas;
    tx.maxFeePerGas = this.maxFeePerGas;
    tx.maxPriorityFeePerGas = this.maxPriorityFeePerGas;

    const transaction = await this.wallet.sendTransaction(tx);
    const receipt = await transaction.wait();
    
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      effectiveGasPrice: receipt.gasPrice.toString(),
      status: receipt.status
    };
  }

  getContract(abi) {
    return new ethers.Contract(this.contractAddress, abi, this.wallet);
  }

  async callContractMethod(abi, methodName, params = []) {
    const contract = this.getContract(abi);
    const result = await contract[methodName](...params);
    return result;
  }

  async sendContractTransaction(abi, methodName, params = [], options = {}) {
    const contract = this.getContract(abi);
    
    const txOptions = {
      gasLimit: options.gasLimit || this.gasLimit,
      maxFeePerGas: options.maxFeePerGas || this.maxFeePerGas,
      maxPriorityFeePerGas: options.maxPriorityFeePerGas || this.maxPriorityFeePerGas
    };

    if (options.value) {
      txOptions.value = ethers.parseEther(options.value.toString());
    }

    const tx = await contract[methodName](...params, txOptions);
    const receipt = await tx.wait();
    
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status,
      logs: receipt.logs
    };
  }

  async transferTokens(abi, toAddress, amount) {
    return await this.sendContractTransaction(
      abi,
      'transfer',
      [toAddress, ethers.parseUnits(amount.toString(), 18)]
    );
  }

  async getTokenBalance(abi, ownerAddress) {
    const balance = await this.callContractMethod(abi, 'balanceOf', [ownerAddress]);
    return ethers.formatUnits(balance, 18);
  }

  async approveTokens(abi, spenderAddress, amount) {
    return await this.sendContractTransaction(
      abi,
      'approve',
      [spenderAddress, ethers.parseUnits(amount.toString(), 18)]
    );
  }

  async estimateGasForContractMethod(abi, methodName, params = []) {
    const contract = this.getContract(abi);
    const estimatedGas = await contract[methodName].estimateGas(...params);
    return estimatedGas.toString();
  }

  async waitForTransaction(txHash, confirmations = 1) {
    const receipt = await this.provider.waitForTransaction(txHash, confirmations);
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status
    };
  }

  async getTransaction(txHash) {
    const tx = await this.provider.getTransaction(txHash);
    return {
      hash: tx.hash,
      from: tx.from,
      to: tx.to,
      value: ethers.formatEther(tx.value),
      gasLimit: tx.gasLimit.toString(),
      gasPrice: tx.gasPrice ? ethers.formatUnits(tx.gasPrice, 'gwei') : null,
      nonce: tx.nonce,
      data: tx.data,
      chainId: tx.chainId
    };
  }

  async getTransactionReceipt(txHash) {
    const receipt = await this.provider.getTransactionReceipt(txHash);
    if (!receipt) return null;
    
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status,
      from: receipt.from,
      to: receipt.to,
      logs: receipt.logs
    };
  }

  async getCurrentGasPrice() {
    const feeData = await this.provider.getFeeData();
    return {
      gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') : null,
      maxFeePerGas: feeData.maxFeePerGas ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') : null,
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') : null
    };
  }

  async getBlockNumber() {
    return await this.provider.getBlockNumber();
  }

  async signMessage(message) {
    return await this.wallet.signMessage(message);
  }

  async verifyMessage(message, signature) {
    const recoveredAddress = ethers.verifyMessage(message, signature);
    return recoveredAddress.toLowerCase() === this.wallet.address.toLowerCase();
  }

  getWalletAddress() {
    return this.wallet.address;
  }

  async getNonce() {
    return await this.provider.getTransactionCount(this.wallet.address);
  }

  async sendRawTransaction(signedTx) {
    const tx = await this.provider.broadcastTransaction(signedTx);
    const receipt = await tx.wait();
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status
    };
  }

  async buildTransaction(to, value, data = '0x', nonce = null) {
    const txNonce = nonce !== null ? nonce : await this.getNonce();
    
    return {
      to: to,
      value: ethers.parseEther(value.toString()),
      data: data,
      nonce: txNonce,
      gasLimit: this.gasLimit,
      maxFeePerGas: this.maxFeePerGas,
      maxPriorityFeePerGas: this.maxPriorityFeePerGas,
      chainId: (await this.provider.getNetwork()).chainId
    };
  }

  async signTransaction(tx) {
    return await this.wallet.signTransaction(tx);
  }
}

class MultiWalletService {
  constructor(rpcUrl) {
    this.provider = new ethers.JsonRpcProvider(rpcUrl);
    this.wallets = new Map();
  }

  addWallet(name, privateKey) {
    const wallet = new ethers.Wallet(privateKey, this.provider);
    this.wallets.set(name, wallet);
    return wallet.address;
  }

  getWallet(name) {
    return this.wallets.get(name);
  }

  async sendETHFromWallet(walletName, toAddress, amount) {
    const wallet = this.getWallet(walletName);
    if (!wallet) throw new Error('Wallet not found');

    const tx = {
      to: toAddress,
      value: ethers.parseEther(amount.toString())
    };

    const transaction = await wallet.sendTransaction(tx);
    const receipt = await transaction.wait();
    
    return {
      from: wallet.address,
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status
    };
  }

  async batchSendETH(walletName, recipients) {
    const wallet = this.getWallet(walletName);
    if (!wallet) throw new Error('Wallet not found');

    const transactions = [];
    
    for (const recipient of recipients) {
      const tx = {
        to: recipient.address,
        value: ethers.parseEther(recipient.amount.toString())
      };

      const transaction = await wallet.sendTransaction(tx);
      transactions.push(transaction);
    }

    const receipts = await Promise.all(transactions.map(tx => tx.wait()));
    
    return receipts.map(receipt => ({
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status
    }));
  }
}

